/**
 * Creates or updates the ProjectStatus sheet
 */
function createOrUpdateProjectStatusSheet(ss) {
  let sheet = ss.getSheetByName('ProjectStatus');
  if (!sheet) {
    sheet = ss.insertSheet('ProjectStatus');
  }

  // Set headers
  const headers = ['StatusID', 'StatusName', 'Description', 'NextAllowedStatuses', 'Color', 'Active'];
  sheet.getRange(1, 1, 1, headers.length).setValues([headers]);

  // Add sample statuses
  const sampleStatuses = [
    ['S001', 'Draft', 'Initial project creation', 'Approved,Cancelled', '#yellow', true],
    ['S002', 'Approved', 'Project approved for execution', 'In Progress', '#green', true],
    ['S003', 'In Progress', 'Project currently being worked on', 'Completed,On Hold', '#blue', true],
    ['S004', 'Completed', 'Project finished', '', '#purple', true],
    ['S005', 'On Hold', 'Project temporarily paused', 'In Progress,Cancelled', '#orange', true],
    ['S006', 'Cancelled', 'Project cancelled', '', '#red', true]
  ];

  sheet.getRange(2, 1, sampleStatuses.length, sampleStatuses[0].length)
    .setValues(sampleStatuses);

  // Add checkbox for Active
  const activeRange = sheet.getRange(2, 6, 999, 1);
  const activeRule = SpreadsheetApp.newDataValidation()
    .requireCheckbox()
    .build();
  activeRange.setDataValidation(activeRule);

  formatSheet(sheet);
}

/**
 * Creates or updates the Validations sheet
 */
function createOrUpdateValidationsSheet(ss) {
  let sheet = ss.getSheetByName('Validations');
  if (!sheet) {
    sheet = ss.insertSheet('Validations');
  }

  // Set headers
  const headers = ['FieldName', 'RuleType', 'Min', 'Max', 'Regex', 'ErrorMessage', 'DependsOn'];
  sheet.getRange(1, 1, 1, headers.length).setValues([headers]);

  // Add rule type validation
  const ruleTypeRange = sheet.getRange(2, 2, 999, 1);
  const ruleTypes = ['TEXT_LENGTH', 'NUMBER_RANGE', 'REGEX', 'DATE_RANGE', 'CUSTOM_LOGIC'];
  const ruleTypeValidation = SpreadsheetApp.newDataValidation()
    .requireValueInList(ruleTypes)
    .build();
  ruleTypeRange.setDataValidation(ruleTypeValidation);

  // Add sample validation rules
  const sampleRules = [
    ['ProjectName', 'TEXT_LENGTH', '3', '50', '', 'Project name must be 3-50 characters', ''],
    ['Budget', 'NUMBER_RANGE', '0', '', '', 'Budget must be greater than 0', ''],
    ['Email', 'REGEX', '', '', '^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$', 'Invalid email format', '']
  ];

  sheet.getRange(2, 1, sampleRules.length, sampleRules[0].length)
    .setValues(sampleRules);

  formatSheet(sheet);
}

/**
 * Creates or updates the Logs sheet
 */
function createOrUpdateLogsSheet(ss) {
  let sheet = ss.getSheetByName('Logs');
  if (!sheet) {
    sheet = ss.insertSheet('Logs');
  }

  // Set headers
  const headers = ['Timestamp', 'UserID', 'Action', 'Details', 'IPAddress'];
  sheet.getRange(1, 1, 1, headers.length).setValues([headers]);

  // Format timestamp column
  sheet.getRange(2, 1, 999, 1).setNumberFormat('yyyy-mm-dd hh:mm:ss');

  formatSheet(sheet);
}

/**
 * Creates or updates the Settings sheet
 */
function createOrUpdateSettingsSheet(ss) {
  let sheet = ss.getSheetByName('Settings');
  if (!sheet) {
    sheet = ss.insertSheet('Settings');
  }

  // Set headers
  const headers = ['Key', 'Value', 'Description', 'LastUpdated', 'UpdatedBy'];
  sheet.getRange(1, 1, 1, headers.length).setValues([headers]);

  // Add sample settings
  const sampleSettings = [
    ['DefaultTimezone', 'America/New_York', 'Default timezone for date/time operations', new Date(), 'System'],
    ['EmailNotifications', 'true', 'Enable email notifications', new Date(), 'System'],
    ['AutoBackup', 'true', 'Enable automatic weekly backups', new Date(), 'System']
  ];

  sheet.getRange(2, 1, sampleSettings.length, sampleSettings[0].length)
    .setValues(sampleSettings);

  formatSheet(sheet);
}

/**
 * Applies standard formatting to a sheet
 */
function formatSheet(sheet) {
  // Format headers
  const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn());
  headers.setBackground('#f3f3f3')
    .setFontWeight('bold')
    .setWrap(true);

  // Auto-resize columns
  sheet.autoResizeColumns(1, sheet.getLastColumn());

  // Add alternating row colors
  if (sheet.getLastRow() > 1) {
    const dataRange = sheet.getRange(2, 1, sheet.getLastRow() - 1, sheet.getLastColumn());
    dataRange.applyRowBanding(SpreadsheetApp.BandingTheme.LIGHT_GREY);
  }

  // Freeze header row
  sheet.setFrozenRows(1);
}

/**
 * Protects sensitive sheets from unauthorized edits
 */
function protectAdminSheets(ss) {
  const sensitiveSheets = ['Users', 'Validations', 'Settings'];

  sensitiveSheets.forEach(sheetName => {
    const sheet = ss.getSheetByName(sheetName);
    if (sheet) {
      const protection = sheet.protect();
      protection.setDescription(`Protected ${sheetName} sheet - Admin access only`);

      // Remove all other editors
      protection.removeEditors(protection.getEditors());
      // Only the owner can edit
      protection.addEditor(Session.getEffectiveUser());
    }
  });
}

/**
 * Sets up triggers for logging changes
 */
function setupTriggers() {
  // Remove existing triggers
  const triggers = ScriptApp.getProjectTriggers();
  triggers.forEach(trigger => ScriptApp.deleteTrigger(trigger));

  // Create new trigger for onEdit
  ScriptApp.newTrigger('logSheetEdit')
    .forSpreadsheet(SpreadsheetApp.getActive())
    .onEdit()
    .create();
}

/**
 * Logs edits to the Logs sheet
 */
function logSheetEdit(e) {
  if (!e || !e.source) return;

  const sheet = e.source.getActiveSheet();
  const sheetName = sheet.getName();

  // Don't log changes to the Logs sheet itself
  if (sheetName === 'Logs') return;

  const range = e.range;
  const row = range.getRow();
  const col = range.getColumn();
  const oldValue = e.oldValue || '';
  const newValue = range.getValue();

  const logSheet = e.source.getSheetByName('Logs');
  if (!logSheet) return;

  const logEntry = [
    new Date(),
    Session.getEffectiveUser().getEmail(),
    'Edit',
    `Changed ${sheetName} [${row},${col}] from "${oldValue}" to "${newValue}"`,
    ''  // IP Address (not available in Apps Script)
  ];

  logSheet.appendRow(logEntry);
}

/**
 * Creates a menu item for the spreadsheet
 */
function onOpen() {
  const ui = SpreadsheetApp.getUi();
  ui.createMenu('Admin Setup')
    .addItem('Update Spreadsheet Structure', 'updateMasterAdminSpreadsheet')
    .addToUi();
}
